async function main() {
  // Check if data already exists (idempotent)
  const existingCount = await prisma.word.count();
  if (existingCount > 0) {
    console.log(`Database already has ${existingCount} words, skipping seed.`);
    return;
  }
  console.log("Seeding Gaokao 3500 words...");
  // Insert words with frequency ranking
  for (let i = 0; i < words.length; i++) {
    const w = words[i];
    await prisma.word.create({
      data: {
        word: w.word,
        phonetics: w.phonetics,
        partOfSpeech: w.pos,
        meaning: w.meaning,
        gaokaoMeaning: w.gaokao,
        frequency: i + 1,
        difficulty: w.word.length <= 3 ? 3 : w.word.length <= 7 ? 5 : 7,
        examples: JSON.stringify([]),
        collocations: JSON.stringify([]),
        synonyms: JSON.stringify([]),
        antonyms: JSON.stringify([]),
      },
    });

    if ((i + 1) % 100 === 0) {
      console.log(`  Seeded ${i + 1} words...`);
    }
  }

  console.log(`Done! Seeded ${words.length} words.`);
  console.log("\nNext steps:");
  console.log("  1. Run: npx prisma db push");
  console.log("  2. Run: npx tsx prisma/seed.ts");
  console.log("  3. Run: npm run dev");
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
